mapper.select:
SELECT s.id AS id, s.name AS name, s.sex AS sex, s.birth AS birth, c.class_name AS className, m.major_name AS majorName, e.education_name AS educationName, s.update_time AS updateTime, COUNT(sd.student_id) AS disciplineCount, SUM(sd.deduction_points) AS deductionPoints FROM student s LEFT JOIN class c ON s.class_id = c.id LEFT JOIN major m ON s.major_id = m.id LEFT JOIN education e ON s.education_id = e.id LEFT JOIN student_discipline sd ON s.id = sd.student_id
AND s.name LIKE CONCAT('%', #{name}, '%')
AND e.education_name = #{educationName}
AND c.class_name = #{className}
GROUP BY s.id
